import heapq

nodes = set()
deps = {}  # node -> set of nodes it depends on

with open("deps.txt") as f:
    for line in f:
        line = line.strip()
        if not line or "->" not in line:
            continue
        a, b = line.split("->", 1)
        a, b = a.strip(), b.strip()
        if not a or not b:
            continue
        nodes.add(a)
        nodes.add(b)
        if a != b:
            deps.setdefault(a, set()).add(b)

# Build indegree (number of unmet dependencies) and reverse adjacency
indegree = {n: 0 for n in nodes}
dependents = {n: [] for n in nodes}  # dep -> list of nodes that depend on it
for a, ds in deps.items():
    indegree[a] = len(ds)
    for b in ds:
        dependents[b].append(a)

heap = [n for n in nodes if indegree[n] == 0]
heapq.heapify(heap)

order = []
while heap:
    n = heapq.heappop(heap)
    order.append(n)
    for m in dependents[n]:
        indegree[m] -= 1
        if indegree[m] == 0:
            heapq.heappush(heap, m)

