import heapq
from collections import defaultdict


def main():
    with open("deps.txt", "r") as f:
        lines = f.readlines()

    nodes = set()
    edges = set()  # (dependent, dependency): dependent depends on dependency

    for line in lines:
        line = line.strip()
        if not line:
            continue
        if "->" not in line:
            continue
        a, b = line.split("->", 1)
        a = a.strip()
        b = b.strip()
        if not a or not b:
            continue
        nodes.add(a)
        nodes.add(b)
        if a == b:
            continue
        edges.add((a, b))

    adj = defaultdict(set)  # prerequisite -> set of dependents
    in_degree = {n: 0 for n in nodes}

    for a, b in edges:
        # a depends on b, so b must be printed before a
        adj[b].add(a)
        in_degree[a] += 1

    heap = [n for n in nodes if in_degree[n] == 0]
    heapq.heapify(heap)

    result = []
    while heap:
        node = heapq.heappop(heap)
        result.append(node)
        for nxt in adj.get(node, ()):
            in_degree[nxt] -= 1
            if in_degree[nxt] == 0:
                heapq.heappush(heap, nxt)

    for name in result:
        print(name)


