        if op == "PUSH":
            stack.append(int(parts[1]))
        elif op == "ADD":
            a = stack.pop()
            b = stack.pop()
            stack.append(a + b)
        elif op == "SUB":
            # first-popped is 'a', second-popped is 'b'
            # result = second-popped minus first-popped
            a = stack.pop()
            b = stack.pop()
            stack.append(b - a)
        elif op == "MUL":
            a = stack.pop()
            b = stack.pop()
            stack.append(a * b)
        elif op == "DUP":
            stack.append(stack[-1])
        elif op == "SWAP":
            stack[-1], stack[-2] = stack[-2], stack[-1]
        else:
            raise ValueError(f"Unknown op: {op}")

