def read_grid(filename):
    """Read the grid from file."""
    with open(filename, 'r') as f:
        lines = f.read().strip().split('\n')
    return [list(line) for line in lines]

def count_neighbors(grid, row, col):
    """Count live neighbors on a torus."""
    rows = len(grid)
    cols = len(grid[0])
    count = 0

    for dr in [-1, 0, 1]:
        for dc in [-1, 0, 1]:
            if dr == 0 and dc == 0:
                continue
            r = (row + dr) % rows
            c = (col + dc) % cols
            if grid[r][c] == '#':
                count += 1

    return count

def next_generation(grid):
    """Calculate the next generation."""
    rows = len(grid)
    cols = len(grid[0])
    new_grid = [['.' for _ in range(cols)] for _ in range(rows)]

    for row in range(rows):
        for col in range(cols):
            neighbors = count_neighbors(grid, row, col)

            if grid[row][col] == '#':
                # Live cell survives with 2-3 neighbors
                if neighbors in [2, 3]:
                    new_grid[row][col] = '#'
            else:
                # Dead cell becomes alive with exactly 3 neighbors
                if neighbors == 3:
                    new_grid[row][col] = '#'

    return new_grid

def print_grid(grid):
    """Print the grid."""
    for row in grid:
        print(''.join(row))

